###############################################################################
#HEADER

#This function allows you to display one histogram per band in your dataset,
#showing the distribution of pixels value within each class.

#Inputs:
# - df_input: Pandas DataFrame as generated by the PyRaTe labelling function.

#Outputs: None

###############################################################################

#Libraries importation:--------------------------------------------------------

import seaborn as sns
import matplotlib.pyplot as plt

#Function definition:----------------------------------------------------------

def dataset_statistics(df_input):
    
    nb_columns = len(df_input.columns)
    
    for col in range(nb_columns-1):
        
        plt.figure()
        sns.histplot(data=df_input,x='band_'+str(col),hue='label')
        plt.title('Band '+str(col)+' histogram')